-- Recalculate counters from seeded approved and pending/rejected reviews.
update obstacle_feature f set reviews_count = coalesce(s.cnt, 0), last_reviewed_at = s.last_reviewed_at from (select feature_id, count(*) cnt, max(created_at) last_reviewed_at from obstacle_review group by feature_id) s where f.id = s.feature_id;
update obstacle_feature f set reviews_count = 0, last_reviewed_at = null where not exists (select 1 from obstacle_review r where r.feature_id = f.id);
update obstacle_feature f set severity_estimate = s.avg_severity from (select feature_id, round(avg(severity))::smallint avg_severity from obstacle_review where status = 'APPROVED' group by feature_id) s where f.id = s.feature_id;
update obstacle_feature_obstacle_score s set reviews_count = coalesce(x.cnt, 0), severity_estimate = coalesce(x.avg_severity, s.severity_estimate) from (select r.feature_id, ro.obstacle_type, count(*) cnt, round(avg(nullif(ro.severity, 0)))::smallint avg_severity from obstacle_review r join obstacle_review_obstacle ro on ro.review_id = r.id where r.status = 'APPROVED' group by r.feature_id, ro.obstacle_type) x where s.feature_id = x.feature_id and s.obstacle_type = x.obstacle_type;
